import com.evolveum.midpoint.xml.ns._public.common.common_3.*
import com.evolveum.midpoint.prism.delta.*
import com.evolveum.midpoint.prism.path.*
import com.evolveum.midpoint.prism.PrismReferenceValue

def KOHA_OID = '9b5a7c81-47aa-42ac-9a08-4de8b64935af'
def user = input

// Resolver los OID de shadow Koha desde linkRef. Con noFetch el shadow vive
// en repo; resolvemos via repositoryService (no toca el conector Koha).
def kohaShadowOids = []
(user.linkRef ?: []).each { ref ->
    if (ref?.oid == null) return
    try {
        def sh = midpoint.repositoryService.getObject(ShadowType.class, ref.oid, null,
            new com.evolveum.midpoint.schema.result.OperationResult('getShadow'))
        if (sh != null && sh.asObjectable().resourceRef != null
                && sh.asObjectable().resourceRef.oid == KOHA_OID) {
            kohaShadowOids << ref.oid
        }
    } catch (ignored) {}
}

if (kohaShadowOids.isEmpty()) {
    return
}

// UNLINK PURO a nivel REPOSITORIO (raw): delete del linkRef por OID de shadow.
// repositoryService.modifyObject NO dispara clockwork ni provisioning => no
// llama al conector Koha (suma-nunca-resta del lado MidPoint). El shadow Koha
// persiste; solo se rompe la referencia user->shadow.
def prismContext = midpoint.prismContext
def refValues = kohaShadowOids.collect { oid ->
    def rv = prismContext.itemFactory().createReferenceValue(oid, ShadowType.COMPLEX_TYPE)
    rv
}

def delta = prismContext.deltaFor(UserType.class)
    .item(UserType.F_LINK_REF)
    .delete(refValues as Object[])
    .asObjectDelta(user.oid)

def result = new com.evolveum.midpoint.schema.result.OperationResult('unlinkKoha')
midpoint.repositoryService.modifyObject(UserType.class, user.oid,
    delta.getModifications(), result)

log.info('UNLINK-KOHA user={} ({}) loc={} shadowsRemoved={}',
    user.name, user.oid, user.locality, kohaShadowOids.size())
